#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    int search(vector<int>& nums, int target) {
        if (find(nums.begin(), nums.end(), target) == nums.end()) return -1;
        return distance(nums.begin(), find(nums.begin(), nums.end(), target));
    }
};

